/**
 * Assets API — Frontend library for investing endpoints
 *
 * Calls the backend /api/investing/* endpoints instead of localStorage.
 * The backend handles DriveWealth integration or simulation.
 */
import api from './api';

// ── Instruments ─────────────────────────────────────

/**
 * Fetch all available instruments (stocks + crypto)
 * @returns {Promise<Array>} instruments list
 */
export async function fetchInstruments() {
    const res = await api.get('/investing/instruments');
    return res.data.data?.instruments || [];
}

// ── Quotes ──────────────────────────────────────────

/**
 * Fetch a price quote + optional chart history
 * @param {string} symbol
 * @param {string} [timeRange] — '1D', '1W', '1M', '1Y', 'ALL'
 * @returns {Promise<{ quote, history }>}
 */
export async function fetchQuote(symbol, timeRange) {
    const params = timeRange ? `?timeRange=${timeRange}` : '';
    const res = await api.get(`/investing/quote/${symbol}${params}`);
    return res.data.data || {};
}

// ── Positions ───────────────────────────────────────

/**
 * Fetch user's portfolio (all positions enriched with current prices)
 * @returns {Promise<{ positions, totalValue, source }>}
 */
export async function fetchPositions() {
    const res = await api.get('/investing/positions');
    return res.data.data || { positions: [], totalValue: 0 };
}

// ── Orders ──────────────────────────────────────────

/**
 * Place a buy/sell order
 * @param {{ symbol: string, side: 'buy'|'sell', amountCents: number }} params
 * @returns {Promise<{ order, source }>}
 */
export async function placeOrder({ symbol, side, amountCents }) {
    const res = await api.post('/investing/orders', { symbol, side, amountCents });
    return res.data.data || {};
}

/**
 * Fetch order history
 * @param {string} [symbol] — optional filter
 * @returns {Promise<Array>}
 */
export async function fetchOrders(symbol) {
    const params = symbol ? `?symbol=${symbol}` : '';
    const res = await api.get(`/investing/orders${params}`);
    return res.data.data?.orders || [];
}

