// Deprecated: now handled by backend
export function getSimulatedPrice(basePrice) {
    const variation = (Math.random() - 0.5) * 0.02 * basePrice;
    return basePrice + variation;
}

export function getDailyChange(symbol) {
    const seed = symbol.split('').reduce((a, c) => a + c.charCodeAt(0), 0);
    return Math.round(((Math.sin(seed + Date.now() / 86400000) * 50) % 5) * 100) / 100;
}

