"use client";

import { useState, useEffect, useCallback } from "react";
import { useAuth } from "@/context/AuthContext";
import { useRouter } from "next/navigation";
import PriceChart from "@/components/PriceChart";
import { fetchInstruments, fetchQuote, fetchPositions } from "@/lib/assets";
import { ArrowLeft, Loader2, TrendingUp } from "lucide-react";

export default function StocksPage() {
    const { user, loading } = useAuth();
    const router = useRouter();

    const [instruments, setInstruments] = useState([]);
    const [stocksWithPrices, setStocksWithPrices] = useState([]);
    const [positions, setPositions] = useState([]);
    const [totalValue, setTotalValue] = useState(0);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        if (!loading && !user) router.push("/login");
    }, [user, loading]);

    const loadData = useCallback(async () => {
        try {
            // Fetch instruments (filter out BTC — stocks only)
            const allInstruments = await fetchInstruments();
            const stocks = allInstruments.filter(i => i.type === 'equity');
            setInstruments(stocks);

            // Fetch quotes for each stock
            const withPrices = await Promise.all(
                stocks.map(async (stock) => {
                    try {
                        const data = await fetchQuote(stock.symbol, '1D');
                        return {
                            ...stock,
                            price: data.quote?.price || 0,
                            changePct: data.quote?.changePct || 0,
                            chartData: data.history || [],
                        };
                    } catch {
                        return { ...stock, price: 0, changePct: 0, chartData: [] };
                    }
                })
            );
            setStocksWithPrices(withPrices);

            // Fetch portfolio
            const portfolio = await fetchPositions();
            setPositions(portfolio.positions || []);
            setTotalValue(portfolio.totalValue || 0);
        } catch (err) {
            console.error("Failed to load stocks:", err);
        } finally {
            setIsLoading(false);
        }
    }, []);

    useEffect(() => {
        if (user) loadData();
    }, [user]);

    if (loading || !user) return null;

    if (isLoading) {
        return (
            <div className="min-h-screen bg-white dark:bg-black flex items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-cashapp" />
            </div>
        );
    }

    const stockPositions = positions.filter(p => p.assetType === 'equity');
    const portfolioValue = stockPositions.reduce((sum, p) => sum + p.marketValue, 0);

    return (
        <div className="min-h-screen bg-white dark:bg-black pb-24">
            {/* Header */}
            <div className="flex items-center space-x-4 p-6">
                <button onClick={() => router.back()} className="p-2 hover:bg-gray-100 dark:hover:bg-zinc-800 rounded-full transition-all">
                    <ArrowLeft className="w-6 h-6" />
                </button>
                <h1 className="text-2xl font-bold">Stocks</h1>
            </div>

            {/* Portfolio Value */}
            {portfolioValue > 0 && (
                <div className="px-6 mb-6">
                    <div className="p-5 bg-gradient-to-br from-cashapp/10 to-blue-500/5 rounded-3xl border border-cashapp/10">
                        <p className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-1">Portfolio Value</p>
                        <p className="text-3xl font-bold">${portfolioValue.toFixed(2)}</p>
                    </div>
                </div>
            )}

            {/* Promo Banner */}
            {portfolioValue === 0 && (
                <div className="px-6 mb-6">
                    <div className="p-5 bg-gradient-to-br from-blue-500/10 to-purple-500/5 rounded-3xl border border-blue-200/20 dark:border-blue-800/20">
                        <div className="flex items-center space-x-3 mb-2">
                            <TrendingUp className="w-5 h-5 text-blue-500" />
                            <p className="font-bold text-sm">Start investing with as little as $1</p>
                        </div>
                        <p className="text-xs text-gray-500">Buy fractional shares of your favorite companies</p>
                    </div>
                </div>
            )}

            {/* Stock List */}
            <div className="px-6 space-y-2">
                {stocksWithPrices.map(stock => {
                    const isUp = stock.changePct >= 0;
                    const holding = positions.find(p => p.symbol === stock.symbol);

                    return (
                        <button
                            key={stock.symbol}
                            onClick={() => router.push(`/stocks/${stock.symbol}`)}
                            className="w-full flex items-center justify-between p-4 rounded-2xl hover:bg-gray-50 dark:hover:bg-zinc-900 transition-all group"
                        >
                            <div className="flex items-center space-x-4">
                                <div className="w-12 h-12 rounded-full flex items-center justify-center text-xl shadow-sm border border-gray-100 dark:border-zinc-800"
                                    style={{ backgroundColor: stock.color + '15' }}>
                                    {stock.icon}
                                </div>
                                <div className="text-left">
                                    <p className="font-bold group-hover:text-cashapp transition-colors">{stock.symbol}</p>
                                    <p className="text-sm text-gray-500">{stock.name}</p>
                                    {holding && (
                                        <p className="text-xs text-gray-400">{holding.quantity.toFixed(4)} shares</p>
                                    )}
                                </div>
                            </div>

                            <div className="flex items-center space-x-4">
                                {/* Mini Chart */}
                                <div className="w-16 h-8">
                                    <PriceChart data={stock.chartData.slice(-30)} color={stock.color} height={32} />
                                </div>
                                <div className="text-right">
                                    <p className="font-bold">${stock.price.toFixed(2)}</p>
                                    <p className={`text-sm font-bold ${isUp ? 'text-cashapp' : 'text-red-500'}`}>
                                        {isUp ? '+' : ''}{stock.changePct.toFixed(2)}%
                                    </p>
                                </div>
                            </div>
                        </button>
                    );
                })}
            </div>
        </div>
    );
}
